// core/tree/engine/TreeSelection.checkbox.ts

import type { TreeNode } from '../models/TreeNode';

export type CheckboxSelection = {
  checked: boolean;
  partialChecked?: boolean;
};

/**
 * Build a map of key → node and key → parentKey for fast lookups.
 */
function buildNodeMaps(nodes: TreeNode[]) {
  const nodeMap = new Map<string, TreeNode>();
  const parentMap = new Map<string, string>();

  const walk = (list: TreeNode[], parentKey?: string) => {
    for (const node of list) {
      const key = String(node.key);
      nodeMap.set(key, node);
      if (parentKey !== undefined) {
        parentMap.set(key, parentKey);
      }
      if (node.children?.length) {
        walk(node.children, key);
      }
    }
  };
  walk(nodes);
  return { nodeMap, parentMap };
}

/**
 * Set all descendants of a node to checked / unchecked.
 * Respects `selectable: false` — non-selectable nodes are skipped
 * but their children are still traversed.
 */
function propagateDown(
  node: TreeNode,
  checked: boolean,
  result: Record<string, CheckboxSelection>,
) {
  if (node.children?.length) {
    for (const child of node.children) {
      const childKey = String(child.key);
      const isSelectable = child.selectable !== false && !child.disabled;

      if (isSelectable) {
        result[childKey] = { checked, partialChecked: false };
      }

      // Always recurse into children
      if (child.children?.length) {
        propagateDown(child, checked, result);
      }

      // If this child is non-selectable but has children, update its partial state
      if (!isSelectable && child.children?.length) {
        updateParentState(child, result);
      }
    }
  }
}

/**
 * Recalculate checked/partial state for a parent based on its selectable children.
 * Non-selectable parents get partialChecked/checked based on their descendants.
 */
function updateParentState(
  node: TreeNode,
  result: Record<string, CheckboxSelection>,
) {
  if (!node.children?.length) return;

  let allChecked = true;
  let anyChecked = false;
  let hasSelectableChild = false;

  for (const child of node.children) {
    const childKey = String(child.key);
    const childState = result[childKey];
    const childIsSelectable = child.selectable !== false && !child.disabled;

    if (childIsSelectable) {
      hasSelectableChild = true;
      if (childState?.checked) {
        anyChecked = true;
      } else {
        allChecked = false;
      }
    } else if (child.children?.length) {
      // Non-selectable node with children: check its partial/checked state
      if (childState?.checked) {
        anyChecked = true;
      } else if (childState?.partialChecked) {
        anyChecked = true;
        allChecked = false;
      } else {
        allChecked = false;
      }
    }
  }

  if (!hasSelectableChild && !anyChecked) {
    allChecked = false;
  }

  const key = String(node.key);
  const parentIsSelectable = node.selectable !== false && !node.disabled;

  if (allChecked && anyChecked) {
    result[key] = { checked: parentIsSelectable, partialChecked: !parentIsSelectable };
  } else if (anyChecked) {
    result[key] = { checked: false, partialChecked: true };
  } else {
    delete result[key];
  }
}

/**
 * Walk up from a node to all ancestors and recalculate their states.
 */
function propagateUp(
  nodeKey: string,
  parentMap: Map<string, string>,
  nodeMap: Map<string, TreeNode>,
  result: Record<string, CheckboxSelection>,
) {
  let currentKey = nodeKey;
  while (parentMap.has(currentKey)) {
    const parentKey = parentMap.get(currentKey)!;
    const parentNode = nodeMap.get(parentKey);
    if (!parentNode) break;
    updateParentState(parentNode, result);
    currentKey = parentKey;
  }
}

/**
 * Toggle checkbox selection with PrimeReact cascading behavior:
 * - Checking a parent checks all selectable descendants
 * - Unchecking a parent unchecks all selectable descendants
 * - Nodes with `selectable: false` or `disabled: true` are never directly checked
 * - Partial checked state propagates up to ancestors
 *
 * @param prev      Current selection state
 * @param node      The node being toggled (just needs .key)
 * @param allNodes  The full tree (needed for parent/child traversal)
 */
export function toggleCheckboxSelection(
  prev: Record<string, CheckboxSelection> | null | undefined,
  node: TreeNode,
  allNodes?: TreeNode[],
): Record<string, CheckboxSelection> {
  const key = String(node.key);
  const next = { ...(prev ?? {}) };

  if (!allNodes?.length) {
    // Fallback: no tree context, toggle single node
    const wasChecked = !!next[key]?.checked;
    next[key] = { checked: !wasChecked, partialChecked: false };
    return next;
  }

  const { nodeMap, parentMap } = buildNodeMaps(allNodes);
  const fullNode = nodeMap.get(key);

  if (!fullNode) {
    const wasChecked = !!next[key]?.checked;
    next[key] = { checked: !wasChecked, partialChecked: false };
    return next;
  }

  // Check if this node is selectable
  const isSelectable = fullNode.selectable !== false && !fullNode.disabled;

  // Determine the new checked state
  const wasChecked = !!next[key]?.checked;
  const newChecked = !wasChecked;

  // Set this node (only if selectable)
  if (isSelectable) {
    next[key] = { checked: newChecked, partialChecked: false };
  }

  // Cascade down to all descendants
  if (fullNode.children?.length) {
    propagateDown(fullNode, newChecked, next);
  }

  // If this node is not selectable but has children, recalculate its own state
  if (!isSelectable && fullNode.children?.length) {
    updateParentState(fullNode, next);
  }

  // Propagate up to all ancestors
  propagateUp(key, parentMap, nodeMap, next);

  // Clean up: remove unchecked+non-partial entries
  for (const k of Object.keys(next)) {
    if (!next[k].checked && !next[k].partialChecked) {
      delete next[k];
    }
  }

  return next;
}
